import{_ as e,o as t,c as r,R as a}from"./chunks/framework.eDbi1Hhd.js";const u=JSON.parse('{"title":"为什么我需要 Prettier","description":"","frontmatter":{},"headers":[],"relativePath":"blogs/2023/02/why-I-need-prettier.md","filePath":"blogs/2023/02/why-I-need-prettier.md","lastUpdated":1677803243000}'),i={name:"blogs/2023/02/why-I-need-prettier.md"},n=a('<h1 id="为什么我需要-prettier" tabindex="-1">为什么我需要 Prettier <a class="header-anchor" href="#为什么我需要-prettier" aria-label="Permalink to &quot;为什么我需要 Prettier&quot;">​</a></h1><p>2022 年，<a href="https://antfu.me/" target="_blank" rel="noreferrer">antfu</a> 发布一篇博文 <a href="https://antfu.me/posts/why-not-prettier-zh" target="_blank" rel="noreferrer">为什么我不使用 Prettier</a>，里面阐述了他不使用 <a href="https://prettier.io/" target="_blank" rel="noreferrer">Prettier</a> 的理由。</p><p>如果你还没有看过，我很建议去看一下。他阐述的理由如下：</p><ul><li>Prettier 是一个固执己见的工具，在部分情况下没法优雅地让 Prettier 格式化结果和自己设想的一致。</li><li>Prettier 的 <code>printWidth</code> 配置可能会破坏行与行之间展示出的差异并且使得代码难以审查，更难过的是你 <a href="https://github.com/prettier/prettier/issues/3468" target="_blank" rel="noreferrer">不能彻底禁用它</a>。</li><li>在大部分情况下，Prettier 需要和 <a href="https://eslint.org/" target="_blank" rel="noreferrer">ESLint</a> 配合使用，这需要大量的配置，而且需要解析两次代码。直接使用 ESLint 会更轻松，更简单，也更快。</li></ul><p>我自己对 Prettier 也有一些思考。</p><h2 id="代码难以审查" tabindex="-1">代码难以审查 <a class="header-anchor" href="#代码难以审查" aria-label="Permalink to &quot;代码难以审查&quot;">​</a></h2><p>不得不承认，<code>printWidth</code> 让我又爱又恨。不止一次，Prettier 格式化导致的换行在 Code Review 时折磨我。如果 <code>printWidth</code> 能够更可控，那样会更轻松。</p><h2 id="集成" tabindex="-1">集成 <a class="header-anchor" href="#集成" aria-label="Permalink to &quot;集成&quot;">​</a></h2><p>对 antfu 而言，他可以只使用 ESLint，因为 <a href="https://github.com/unocss/unocss" target="_blank" rel="noreferrer">UnoCSS</a> 使得他不再需要写样式代码。</p><p>但对我而言，大量 Web 项目使用了 <a href="https://element-plus.org/" target="_blank" rel="noreferrer">element-plus</a> 等 UI 库，往往需要或简单或深度的定制，没办法避开写样式代码。所以在我这里 ESLint 和 Stylelint 都是必需的。</p><p>ESLint 和 Stylelint 都提供了代码格式化的规则，但它们彼此不是互通的！如果我想要获得一样的格式，除了自己查看所有的规则然后自定义外，就只有引入一个可以和 ESLint、Stylelint 集成的 formatter 一条路可走。</p><p>很明显，自己查看所有的规则然后自定义太累了，我绝不愿意这么做，那我就只能引入一个可以和 ESLint、Stylelint 集成的 formatter。<a href="https://github.com/dprint/dprint" target="_blank" rel="noreferrer">dprint</a> 和 <a href="https://github.com/rome/tools" target="_blank" rel="noreferrer">Rome</a> 都还属于早期阶段，我只能选择 Prettier。</p><p>值得一提的是，Stylelint 打算 <a href="https://github.com/stylelint/stylelint/issues/6342" target="_blank" rel="noreferrer">移除所有和格式化有关的规则</a>，这下我更离不开 Prettier 了。</p><h2 id="性能" tabindex="-1">性能 <a class="header-anchor" href="#性能" aria-label="Permalink to &quot;性能&quot;">​</a></h2><p>在不得不使用 Prettier 之后，性能是迎面而来的问题。</p><p>和 ESLint、Stylelint 集成后，代码解析至少有三次：ESLint、Stylelint 和 Prettier。这其中有部分是重复的，导致 lint 使用了比预期还要更多的时间。可惜的是，这在目前是无法避免的问题，因为 ESLint、Stylelint 和 Prettier 对 AST 的解析不完全一致，所以没办法复用 AST。</p><p>就目前来看，Rome 是我最期望得到的工具，但它开发得有点慢，恐怕在一两年内也没法和 ESLint、Stylelint、Prettier 相提并论。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>如果你不需要写样式代码，ESLint 就足够了。否则，我还是建议使用 ESLint + Stylelint + Prettier 的组合。</p>',19),l=[n];function o(p,h,s,d,c,f){return t(),r("div",null,l)}const S=e(i,[["render",o]]);export{u as __pageData,S as default};
